const { PrismaClient } = require('@prisma/client');
const prisma = new PrismaClient();

const GRAMMAR_DATA = [
  // ===== BÀI 1 (lesson 0) — Gia đình & quan hệ mở rộng =====
  {lesson:0,content:{title:"1. Question Tags",desc:"Câu hỏi đuôi dùng để xác nhận lại thông tin vừa nói. Câu chính khẳng định thì đuôi phủ định, và ngược lại.",formula:[{text:"Khẳng định, trợ động từ phủ định + S?",classes:"bg-blue-100 text-blue-700 border-blue-300 font-bold"},{text:"Phủ định, trợ động từ khẳng định + S?",classes:"bg-green-100 text-green-700 border-green-300 font-bold"}],practiceList:[{correct:"You're from Hanoi, aren't you?",meaning:"Bạn đến từ Hà Nội, đúng không?"},{correct:"She doesn't know, does she?",meaning:"Cô ấy không biết, đúng không?"},{correct:"He is your cousin, isn't he?",meaning:"Anh ấy là anh họ của bạn, đúng không?"}]}},
  {lesson:0,content:{title:"2. Have got vs Have",desc:"'Have got' phổ biến trong tiếng Anh-Anh (British English) khi nói về sự sở hữu, còn 'have' dùng phổ biến hơn trong tiếng Anh-Mỹ (American English). Cả hai đều đúng.",formula:[{text:"S + have/has got + N (Anh-Anh)",classes:"bg-purple-100 text-purple-700 border-purple-300 font-bold"},{text:"S + have/has + N (Anh-Mỹ)",classes:"bg-pink-100 text-pink-700 border-pink-300 font-bold"}],practiceList:[{correct:"I've got a new neighbour.",meaning:"Tôi có một người hàng xóm mới."},{correct:"She has a colleague called Mark.",meaning:"Cô ấy có một đồng nghiệp tên là Mark."},{correct:"Have you got any relatives in London?",meaning:"Bạn có người thân nào ở London không?"}]}},
  {lesson:0,content:{title:"3. Whose + Possession",desc:"Dùng 'whose' để hỏi một vật/người thuộc về ai, áp dụng cho các quan hệ xã hội mới như colleague, partner, guest.",formula:[{text:"Whose + N + is/are + this/these?",classes:"bg-yellow-100 text-yellow-700 border-yellow-300 font-bold"}],practiceList:[{correct:"Whose guest is this?",meaning:"Đây là khách của ai?"},{correct:"Whose partner is coming tonight?",meaning:"Người bạn đời của ai sẽ đến tối nay?"},{correct:"This is my colleague's bag.",meaning:"Đây là túi của đồng nghiệp tôi."}]}},

  // ===== BÀI 2 (lesson 1) — Tính cách & cảm xúc mở rộng =====
  {lesson:1,content:{title:"1. So ... that",desc:"Dùng 'so + tính từ/trạng từ + that' để nhấn mạnh mức độ dẫn đến một kết quả.",formula:[{text:"S + be + so + adj + that + clause",classes:"bg-indigo-100 text-indigo-700 border-indigo-300 font-bold"}],practiceList:[{correct:"She was so nervous that she couldn't speak.",meaning:"Cô ấy lo lắng đến mức không thể nói được."},{correct:"He was so angry that he left the room.",meaning:"Anh ấy giận đến mức bỏ ra khỏi phòng."},{correct:"It was so cold that we stayed inside.",meaning:"Trời lạnh đến mức chúng tôi phải ở trong nhà."}]}},
  {lesson:1,content:{title:"2. Such a/an ... that",desc:"Dùng 'such a/an + tính từ + danh từ + that' với cùng ý nghĩa nhấn mạnh như 'so...that' nhưng đi với danh từ.",formula:[{text:"S + be + such a/an + adj + N + that + clause",classes:"bg-teal-100 text-teal-700 border-teal-300 font-bold"}],practiceList:[{correct:"It was such a scary film that I covered my eyes.",meaning:"Đó là một bộ phim đáng sợ đến mức tôi phải che mắt."},{correct:"He is such a polite boy that everyone likes him.",meaning:"Cậu ấy là một chàng trai lễ phép đến mức ai cũng yêu mến."},{correct:"She has such an awful cold that she stayed in bed.",meaning:"Cô ấy bị cảm nặng đến mức phải nằm nghỉ trên giường."}]}},
  {lesson:1,content:{title:"3. Be + Adj + Intensifiers",desc:"Dùng các trạng từ chỉ mức độ (really/quite/a bit/very) trước tính từ để diễn tả cảm xúc rõ hơn.",formula:[{text:"S + be + really/quite/a bit/very + adj",classes:"bg-orange-100 text-orange-700 border-orange-300 font-bold"}],practiceList:[{correct:"I'm a bit scared of spiders.",meaning:"Tôi sợ nhện một chút."},{correct:"She's really glad to see you.",meaning:"Cô ấy thực sự rất vui khi gặp bạn."},{correct:"He looked quite pale this morning.",meaning:"Sáng nay anh ấy trông khá nhợt nhạt."}]}},

  // ===== BÀI 3 (lesson 2) — Ngoại hình & thời trang =====
  {lesson:2,content:{title:"1. Look like vs Look",desc:"'Look like + danh từ' dùng để so sánh ngoại hình giống ai/cái gì, còn 'look + tính từ' dùng để miêu tả trạng thái/vẻ ngoài.",formula:[{text:"S + look like + N",classes:"bg-blue-100 text-blue-700 border-blue-300 font-bold"},{text:"S + look + adj",classes:"bg-green-100 text-green-700 border-green-300 font-bold"}],practiceList:[{correct:"He looks like his father.",meaning:"Anh ấy trông giống bố mình."},{correct:"She looks tired today.",meaning:"Hôm nay cô ấy trông có vẻ mệt."},{correct:"This bag looks like leather, but it isn't.",meaning:"Cái túi này trông như da, nhưng không phải."}]}},
  {lesson:2,content:{title:"2. Passive: Be made of",desc:"Dùng câu bị động sơ cấp 'be made of' để nói chất liệu của đồ vật, trang sức.",formula:[{text:"N + is/are + made of + chất liệu",classes:"bg-purple-100 text-purple-700 border-purple-300 font-bold"}],practiceList:[{correct:"This jacket is made of leather.",meaning:"Chiếc áo khoác này được làm từ da."},{correct:"Her earrings are made of gold.",meaning:"Khuyên tai của cô ấy được làm từ vàng."},{correct:"The chain is made of silver.",meaning:"Dây chuyền này được làm từ bạc."}]}},
  {lesson:2,content:{title:"3. Be wearing vs Have got on",desc:"Cả hai cấu trúc đều diễn tả việc đang mặc quần áo, dùng ở Hiện tại tiếp diễn để miêu tả trang phục lúc nói.",formula:[{text:"S + be + wearing + N",classes:"bg-pink-100 text-pink-700 border-pink-300 font-bold"},{text:"S + have/has got on + N",classes:"bg-yellow-100 text-yellow-700 border-yellow-300 font-bold"}],practiceList:[{correct:"She is wearing bright make-up today.",meaning:"Hôm nay cô ấy trang điểm rất nổi bật."},{correct:"He has got a cream jacket on.",meaning:"Anh ấy đang mặc một chiếc áo khoác màu kem."},{correct:"What are you wearing to the party?",meaning:"Bạn sẽ mặc gì đến buổi tiệc?"}]}},

  // ===== BÀI 4 (lesson 3) — Nhà cửa & nội thất mở rộng =====
  {lesson:3,content:{title:"1. Passive (Present Simple)",desc:"Dùng câu bị động ở Hiện tại đơn khi nhấn mạnh hành động lặp lại thường xuyên hơn là người thực hiện.",formula:[{text:"S + am/is/are + V(p.p)",classes:"bg-indigo-100 text-indigo-700 border-indigo-300 font-bold"}],practiceList:[{correct:"The heating is turned on at 6 a.m.",meaning:"Hệ thống sưởi được mở vào 6 giờ sáng."},{correct:"The house is cleaned every day.",meaning:"Ngôi nhà được dọn dẹp mỗi ngày."},{correct:"The curtains are washed once a month.",meaning:"Rèm cửa được giặt một lần mỗi tháng."}]}},
  {lesson:3,content:{title:"2. Need + V-ing",desc:"Dùng 'need + V-ing' (mang nghĩa bị động) để nói một vật cần được sửa chữa hoặc xử lý.",formula:[{text:"N + needs + V-ing",classes:"bg-teal-100 text-teal-700 border-teal-300 font-bold"}],practiceList:[{correct:"The drawer needs fixing.",meaning:"Cái ngăn kéo cần được sửa."},{correct:"The carpet needs cleaning.",meaning:"Tấm thảm cần được làm sạch."},{correct:"This pillow needs washing.",meaning:"Cái gối này cần được giặt."}]}},
  {lesson:3,content:{title:"3. Have got cho nội thất",desc:"Ôn lại 'have got' để mô tả những gì có trong nhà, áp dụng với từ vựng nội thất mới.",formula:[{text:"S + have/has got + furniture",classes:"bg-orange-100 text-orange-700 border-orange-300 font-bold"}],practiceList:[{correct:"We've got a big cupboard in the kitchen.",meaning:"Chúng tôi có một cái tủ lớn trong nhà bếp."},{correct:"My room has got a comfortable armchair.",meaning:"Phòng tôi có một cái ghế bành thoải mái."},{correct:"They haven't got curtains in the living room yet.",meaning:"Họ chưa có rèm cửa trong phòng khách."}]}},

  // ===== BÀI 5 (lesson 4) — Căn hộ & chỗ ở =====
  {lesson:4,content:{title:"1. Passive (Past Simple)",desc:"Dùng câu bị động ở Quá khứ đơn để nhấn mạnh đối tượng chịu tác động đã xảy ra trong quá khứ.",formula:[{text:"S (vật) + was/were + V(p.p)",classes:"bg-blue-100 text-blue-700 border-blue-300 font-bold"}],practiceList:[{correct:"The flat was built in 2010.",meaning:"Căn hộ này được xây vào năm 2010."},{correct:"The room was cleaned yesterday.",meaning:"Phòng đã được dọn dẹp hôm qua."},{correct:"This guest-house was decorated last year.",meaning:"Nhà nghỉ này đã được trang trí lại năm ngoái."}]}},
  {lesson:4,content:{title:"2. Floor: sàn nhà vs tầng",desc:"Từ 'floor' vừa có nghĩa là 'sàn nhà', vừa có nghĩa là 'tầng' trong một tòa nhà — phân biệt qua ngữ cảnh.",formula:[{text:"on the + số thứ tự + floor (tầng mấy)",classes:"bg-green-100 text-green-700 border-green-300 font-bold"},{text:"on the floor (trên sàn nhà)",classes:"bg-purple-100 text-purple-700 border-purple-300 font-bold"}],practiceList:[{correct:"My flat is on the third floor.",meaning:"Căn hộ của tôi ở tầng ba."},{correct:"There is a carpet on the floor.",meaning:"Có một tấm thảm trên sàn nhà."},{correct:"The block has got ten floors.",meaning:"Tòa nhà này có mười tầng."}]}},
  {lesson:4,content:{title:"3. Is there a/an...?",desc:"Dùng để hỏi về sự tồn tại của một loại nhà hoặc tiện nghi trong nơi ở.",formula:[{text:"Is there a/an + N (số ít) + in/at + place?",classes:"bg-pink-100 text-pink-700 border-pink-300 font-bold"}],practiceList:[{correct:"Is there a bathtub in the bathroom?",meaning:"Có bồn tắm trong phòng tắm không?"},{correct:"Is there a closet in the bedroom?",meaning:"Có tủ quần áo trong phòng ngủ không?"},{correct:"Is there any accommodation near the station?",meaning:"Có chỗ ở nào gần nhà ga không?"}]}},

  // ===== BÀI 6 (lesson 5) — Việc nhà & thiết bị =====
  {lesson:5,content:{title:"1. Need + to-V vs Need + V-ing",desc:"'Need + to-V' mang nghĩa chủ động (ai đó cần làm gì), còn 'need + V-ing' mang nghĩa bị động (vật cần được làm gì).",formula:[{text:"S + need(s) + to + V",classes:"bg-yellow-100 text-yellow-700 border-yellow-300 font-bold"},{text:"N + need(s) + V-ing",classes:"bg-indigo-100 text-indigo-700 border-indigo-300 font-bold"}],practiceList:[{correct:"I need to repair the printer.",meaning:"Tôi cần sửa máy in."},{correct:"It needs repairing.",meaning:"Nó cần được sửa."},{correct:"The alarm clock needs a new battery.",meaning:"Cái đồng hồ báo thức cần một viên pin mới."}]}},
  {lesson:5,content:{title:"2. Phrasal Verbs thiết bị",desc:"Các cụm động từ thường gặp khi nói về việc sử dụng/hỏng thiết bị điện trong nhà.",formula:[{text:"turn on/off + thiết bị",classes:"bg-teal-100 text-teal-700 border-teal-300 font-bold"},{text:"break down (hỏng máy)",classes:"bg-orange-100 text-orange-700 border-orange-300 font-bold"}],practiceList:[{correct:"Can you turn off the cooker, please?",meaning:"Bạn có thể tắt bếp giúp tôi không?"},{correct:"The fridge has broken down again.",meaning:"Tủ lạnh lại bị hỏng nữa rồi."},{correct:"Don't forget to turn on the heating.",meaning:"Đừng quên mở hệ thống sưởi nhé."}]}},
  {lesson:5,content:{title:"3. Have something done",desc:"Cấu trúc sơ cấp diễn tả việc nhờ/thuê người khác làm gì đó cho mình, thường dùng với việc sửa chữa.",formula:[{text:"S + have/has + N + V(p.p)",classes:"bg-blue-100 text-blue-700 border-blue-300 font-bold"}],practiceList:[{correct:"I had the TV repaired.",meaning:"Tôi đã nhờ người sửa cái TV."},{correct:"We had the cable fixed yesterday.",meaning:"Hôm qua chúng tôi đã nhờ sửa dây cáp."},{correct:"She is having her printer cleaned.",meaning:"Cô ấy đang nhờ vệ sinh máy in của mình."}]}},
  // ===== BÀI 7 (lesson 6) — Mua sắm mở rộng =====
  {lesson:6,content:{title:"1. Cách hỏi giá cả",desc:"Các mẫu câu thông dụng khi muốn biết giá của một món hàng.",formula:[{text:"How much does it cost?",classes:"bg-teal-100 text-teal-700 border-teal-300 font-bold"},{text:"What is the price?",classes:"bg-purple-100 text-purple-700 border-purple-300 font-bold"}],practiceList:[{correct:"How much does this jacket cost?",meaning:"Cái áo khoác này giá bao nhiêu?"},{correct:"What is the price of this bag?",meaning:"Giá của cái túi này là bao nhiêu?"},{correct:"It costs ten pounds.",meaning:"Nó có giá mười bảng Anh."}]}},
  {lesson:6,content:{title:"2. Xin phép lịch sự với Can/Could",desc:"Sử dụng động từ khuyết thiếu để xin phép lịch sự trong ngữ cảnh cửa hàng.",formula:[{text:"Can/Could I + V(nguyên thể) + please?",classes:"bg-pink-100 text-pink-700 border-pink-300 font-bold"}],practiceList:[{correct:"Could I try this on, please?",meaning:"Tôi có thể thử cái này được không?"},{correct:"Can I have a receipt, please?",meaning:"Tôi có thể xin biên lai được không?"},{correct:"Could I pay by credit card?",meaning:"Tôi có thể trả bằng thẻ tín dụng không?"}]}},
  {lesson:6,content:{title:"3. Đơn vị tiền tệ",desc:"Cách đọc số tiền và sử dụng các đơn vị tiền tệ phổ biến trong tiếng Anh.",formula:[{text:"Số lượng + pound(s)/euro(s)/dollar(s)/cent(s)",classes:"bg-yellow-100 text-yellow-700 border-yellow-300 font-bold"}],practiceList:[{correct:"This discount saves you five pounds.",meaning:"Khoản giảm giá này giúp bạn tiết kiệm năm bảng."},{correct:"The bill is twenty euros.",meaning:"Hóa đơn là hai mươi euro."},{correct:"I only have three dollars in cash.",meaning:"Tôi chỉ có ba đô la tiền mặt."}]}},

  // ===== BÀI 8 (lesson 7) — Cửa hàng & dịch vụ =====
  {lesson:7,content:{title:"1. Where can I find/buy...?",desc:"Mẫu câu hỏi thực tế khi cần tìm mua một mặt hàng cụ thể.",formula:[{text:"Where can I find/buy + N?",classes:"bg-indigo-100 text-indigo-700 border-indigo-300 font-bold"}],practiceList:[{correct:"Where can I buy stamps?",meaning:"Tôi có thể mua tem ở đâu?"},{correct:"Where can I find a pharmacy near here?",meaning:"Tôi có thể tìm thấy một hiệu thuốc gần đây ở đâu?"},{correct:"Where can I find the fitting room?",meaning:"Phòng thử đồ ở đâu vậy?"}]}},
  {lesson:7,content:{title:"2. Is there a ... near here?",desc:"Ôn cấu trúc hỏi sự tồn tại của địa điểm và kết hợp chỉ đường.",formula:[{text:"Is there a + place + near here?",classes:"bg-teal-100 text-teal-700 border-teal-300 font-bold"}],practiceList:[{correct:"Is there a bookshop near here?",meaning:"Có cửa hàng sách nào gần đây không?"},{correct:"Is there a butcher in this street?",meaning:"Có hàng bán thịt nào trên con phố này không?"},{correct:"Yes, it's next to the bakery.",meaning:"Có, nó ở cạnh tiệm bánh."}]}},
  {lesson:7,content:{title:"3. For sale vs On sale",desc:"'For sale' nghĩa là đang được rao bán, 'on sale' nghĩa là đang được giảm giá.",formula:[{text:"be + for sale (đang được bán)",classes:"bg-orange-100 text-orange-700 border-orange-300 font-bold"},{text:"be + on sale (đang giảm giá)",classes:"bg-blue-100 text-blue-700 border-blue-300 font-bold"}],practiceList:[{correct:"This house is for sale.",meaning:"Ngôi nhà này đang được rao bán."},{correct:"These shoes are on sale this week.",meaning:"Đôi giày này đang được giảm giá trong tuần này."},{correct:"Everything in the department store is on sale.",meaning:"Mọi thứ trong trung tâm thương mại đang được giảm giá."}]}},

  // ===== BÀI 9 (lesson 8) — Ngân hàng & bưu điện =====
  {lesson:8,content:{title:"1. Reported Speech sơ cấp",desc:"Tường thuật lại câu nói của người khác, động từ trong câu thường phải lùi một thì.",formula:[{text:"S + said (that) + S + V (lùi thì)",classes:"bg-purple-100 text-purple-700 border-purple-300 font-bold"}],practiceList:[{correct:"She said (that) she needed money.",meaning:"Cô ấy nói rằng cô ấy cần tiền."},{correct:"He said he had lost his cheque book.",meaning:"Anh ấy nói rằng anh ấy đã làm mất sổ séc."},{correct:"They said the form was ready.",meaning:"Họ nói rằng tờ đơn đã sẵn sàng."}]}},
  {lesson:8,content:{title:"2. Fill in a form",desc:"Sử dụng cụm động từ 'fill in' (hoặc 'fill out' trong tiếng Anh-Mỹ) để nói về việc điền thông tin vào đơn/tờ khai.",formula:[{text:"Fill in/out + a form/an application",classes:"bg-pink-100 text-pink-700 border-pink-300 font-bold"}],practiceList:[{correct:"Please fill in this form.",meaning:"Vui lòng điền vào mẫu đơn này."},{correct:"I need to fill out an application for a new account.",meaning:"Tôi cần điền vào đơn xin mở một tài khoản mới."},{correct:"Have you filled in the envelope address?",meaning:"Bạn đã điền địa chỉ trên phong bì chưa?"}]}},
  {lesson:8,content:{title:"3. Send, Post, Deliver",desc:"Các động từ liên quan đến việc gửi thư từ hoặc hàng hóa.",formula:[{text:"Send (gửi đi)",classes:"bg-yellow-100 text-yellow-700 border-yellow-300 font-bold"},{text:"Post (gửi qua bưu điện) / Deliver (giao hàng)",classes:"bg-green-100 text-green-700 border-green-300 font-bold"}],practiceList:[{correct:"I sent her a stamp collection.",meaning:"Tôi đã gửi cho cô ấy một bộ sưu tập tem."},{correct:"Can you post this letter for me?",meaning:"Bạn có thể gửi giúp tôi lá thư này qua bưu điện không?"},{correct:"The post office delivers parcels every morning.",meaning:"Bưu điện giao các bưu phẩm vào mỗi buổi sáng."}]}},

  // ===== BÀI 10 (lesson 9) — Ẩm thực & nấu ăn =====
  {lesson:9,content:{title:"1. Would rather + V",desc:"Dùng để diễn tả điều mình muốn làm hơn so với một lựa chọn khác.",formula:[{text:"S + would rather + V(nguyên thể)",classes:"bg-indigo-100 text-indigo-700 border-indigo-300 font-bold"}],practiceList:[{correct:"I'd rather eat at home.",meaning:"Tôi muốn ăn ở nhà hơn."},{correct:"She would rather have a dessert than a main course.",meaning:"Cô ấy muốn ăn món tráng miệng hơn là món chính."},{correct:"Would you rather cook or order a curry?",meaning:"Bạn muốn tự nấu hay gọi món cà ri hơn?"}]}},
  {lesson:9,content:{title:"2. Prefer ... to ...",desc:"Cấu trúc so sánh sự ưu tiên giữa hai lựa chọn.",formula:[{text:"S + prefer + N/V-ing + to + N/V-ing",classes:"bg-teal-100 text-teal-700 border-teal-300 font-bold"}],practiceList:[{correct:"I prefer Italian food to curry.",meaning:"Tôi thích món Ý hơn món cà ri."},{correct:"She prefers grilled fish to fried fish.",meaning:"Cô ấy thích cá nướng hơn cá chiên."},{correct:"Do you prefer cooking to eating out?",meaning:"Bạn thích tự nấu ăn hơn là ăn ngoài không?"}]}},
  {lesson:9,content:{title:"3. How much/How many",desc:"Ôn 'How much' với danh từ không đếm được và 'How many' với danh từ đếm được trong ngữ cảnh đồ ăn.",formula:[{text:"How much + N (không đếm được)?",classes:"bg-orange-100 text-orange-700 border-orange-300 font-bold"},{text:"How many + N(s) (đếm được)?",classes:"bg-blue-100 text-blue-700 border-blue-300 font-bold"}],practiceList:[{correct:"How much garlic do we need?",meaning:"Chúng ta cần bao nhiêu tỏi?"},{correct:"How many onions are in the soup?",meaning:"Có bao nhiêu củ hành trong món súp?"},{correct:"How much is on the menu today?",meaning:"Hôm nay thực đơn có bao nhiêu món?"}]}},

  // ===== BÀI 11 (lesson 10) — Phương pháp nấu =====
  {lesson:10,content:{title:"1. Passive trong hướng dẫn nấu ăn",desc:"Thường dùng trong các công thức nấu ăn để diễn tả bước chế biến mà không cần nói ai làm.",formula:[{text:"S (Thực phẩm) + am/is/are + V(p.p)",classes:"bg-purple-100 text-purple-700 border-purple-300 font-bold"}],practiceList:[{correct:"The chicken is grilled for 20 minutes.",meaning:"Thịt gà được nướng trong 20 phút."},{correct:"The vegetables are boiled first.",meaning:"Rau củ được luộc trước."},{correct:"The bread is baked at a high temperature.",meaning:"Bánh mì được nướng ở nhiệt độ cao."}]}},
  {lesson:10,content:{title:"2. Should/Must trong nấu ăn",desc:"Sử dụng động từ khuyết thiếu để đưa ra lời khuyên hoặc yêu cầu bắt buộc trong quy trình nấu.",formula:[{text:"You + should/must + V(nguyên thể)",classes:"bg-pink-100 text-pink-700 border-pink-300 font-bold"}],practiceList:[{correct:"You should slice the onion thinly.",meaning:"Bạn nên cắt hành mỏng."},{correct:"You must use fresh ingredients.",meaning:"Bạn phải dùng nguyên liệu tươi."},{correct:"You shouldn't eat raw chicken.",meaning:"Bạn không nên ăn thịt gà còn sống."}]}},
  {lesson:10,content:{title:"3. Đơn vị đo lường khi nấu ăn",desc:"Cách sử dụng các cụm chỉ lượng trong công thức nấu ăn.",formula:[{text:"Số lượng + kilo(s)/litre(s)/gram(s) + of + N",classes:"bg-yellow-100 text-yellow-700 border-yellow-300 font-bold"}],practiceList:[{correct:"Add 200 grams of flour.",meaning:"Thêm 200 gram bột mì."},{correct:"You need a litre of water.",meaning:"Bạn cần một lít nước."},{correct:"Mix a kilo of rice with the curry.",meaning:"Trộn một ký gạo với món cà ri."}]}},

  // ===== BÀI 12 (lesson 11) — Sức khỏe & y tế =====
  {lesson:11,content:{title:"1. Have been to",desc:"Dùng Hiện tại hoàn thành với 'have been to' để hỏi/nói về kinh nghiệm từng đến một nơi.",formula:[{text:"Have/Has + S + (ever) + been to + place?",classes:"bg-indigo-100 text-indigo-700 border-indigo-300 font-bold"}],practiceList:[{correct:"Have you ever been to hospital?",meaning:"Bạn đã từng đến bệnh viện chưa?"},{correct:"She has been to the doctor twice this month.",meaning:"Cô ấy đã đến gặp bác sĩ hai lần trong tháng này."},{correct:"I have never been to a dentist.",meaning:"Tôi chưa từng đến nha sĩ."}]}},
  {lesson:11,content:{title:"2. Should/Shouldn't lời khuyên y tế",desc:"Sử dụng 'should' hoặc 'shouldn't' để đưa ra lời khuyên về sức khỏe.",formula:[{text:"S + should/shouldn't + V",classes:"bg-teal-100 text-teal-700 border-teal-300 font-bold"}],practiceList:[{correct:"You look sick. You should go to the doctor.",meaning:"Trông bạn có vẻ ốm. Bạn nên đi gặp bác sĩ."},{correct:"He shouldn't eat too much fast food.",meaning:"Anh ấy không nên ăn quá nhiều đồ ăn nhanh."},{correct:"If you have a headache, you should rest.",meaning:"Nếu bạn bị đau đầu, bạn nên nghỉ ngơi."}]}},
  {lesson:11,content:{title:"3. Make an appointment",desc:"Cụm động từ thực tế dùng khi muốn đặt lịch khám bệnh.",formula:[{text:"make an appointment + (with/for)",classes:"bg-orange-100 text-orange-700 border-orange-300 font-bold"}],practiceList:[{correct:"I'd like to make an appointment with the doctor.",meaning:"Tôi muốn đặt lịch hẹn với bác sĩ."},{correct:"She made an appointment for an X-ray.",meaning:"Cô ấy đã đặt lịch để chụp X-quang."},{correct:"Can I make an appointment for tomorrow morning?",meaning:"Tôi có thể đặt lịch hẹn cho sáng ngày mai không?"}]}},
  // ===== BÀI 13 (lesson 12) — Thể dục & thể thao mở rộng =====
  {lesson:12,content:{title:"1. Go + V-ing",desc:"Sử dụng với các môn thể thao hoặc hoạt động giải trí có đuôi -ing, thường mang tính di chuyển.",formula:[{text:"S + go/goes/went + V-ing",classes:"bg-blue-100 text-blue-700 border-blue-300 font-bold"}],practiceList:[{correct:"We go diving every summer.",meaning:"Chúng tôi đi lặn biển mỗi mùa hè."},{correct:"He goes climbing at the weekend.",meaning:"Anh ấy đi leo núi vào cuối tuần."},{correct:"They went sailing yesterday.",meaning:"Hôm qua họ đã đi chèo thuyền."}]}},
  {lesson:12,content:{title:"2. Be able to",desc:"Dùng để diễn tả khả năng có thể làm được một việc gì đó, tương đương với can/could nhưng linh hoạt hơn ở các thì.",formula:[{text:"S + be + able to + V(nguyên thể)",classes:"bg-green-100 text-green-700 border-green-300 font-bold"}],practiceList:[{correct:"I'm able to swim 100 metres.",meaning:"Tôi có thể bơi 100 mét."},{correct:"She wasn't able to play tennis last week.",meaning:"Tuần trước cô ấy không thể chơi tennis được."},{correct:"Will you be able to join the athletics club?",meaning:"Bạn sẽ có thể tham gia câu lạc bộ điền kinh không?"}]}},
  {lesson:12,content:{title:"3. So sánh bậc nhất trong thể thao",desc:"Sử dụng tính từ ở dạng so sánh nhất để nói về người/đội/kỷ lục giỏi nhất, nhanh nhất.",formula:[{text:"S + be + the + adj-est/most adj",classes:"bg-purple-100 text-purple-700 border-purple-300 font-bold"}],practiceList:[{correct:"He is the fastest runner on the court.",meaning:"Anh ấy là người chạy nhanh nhất trên sân."},{correct:"She is the strongest swimmer in the gym.",meaning:"Cô ấy là người bơi khỏe nhất trong phòng tập."},{correct:"This is the most exciting athletics event of the year.",meaning:"Đây là sự kiện điền kinh thú vị nhất trong năm."}]}},

  // ===== BÀI 14 (lesson 13) — Sân bay & du lịch =====
  {lesson:13,content:{title:"1. Be going to vs Will",desc:"Ôn cách dùng 'be going to' (kế hoạch đã định) và 'will' (quyết định tức thời/dự đoán) trong ngữ cảnh du lịch.",formula:[{text:"S + am/is/are + going to + V (kế hoạch)",classes:"bg-pink-100 text-pink-700 border-pink-300 font-bold"},{text:"S + will + V (quyết định/dự đoán)",classes:"bg-yellow-100 text-yellow-700 border-yellow-300 font-bold"}],practiceList:[{correct:"We are going to fly to Paris next month.",meaning:"Chúng tôi sẽ bay đến Paris vào tháng tới."},{correct:"I think the flight will be delayed.",meaning:"Tôi nghĩ chuyến bay sẽ bị trễ."},{correct:"I'll check my luggage now.",meaning:"Tôi sẽ kiểm tra hành lý của mình ngay bây giờ."}]}},
  {lesson:13,content:{title:"2. By the time",desc:"Giới thiệu Past Perfect qua cụm 'by the time' để nói một việc đã hoàn tất trước một thời điểm khác trong quá khứ.",formula:[{text:"By the time + S + V(qkđ), S + had + V(p.p)",classes:"bg-indigo-100 text-indigo-700 border-indigo-300 font-bold"}],practiceList:[{correct:"By the time we arrived, the flight had left.",meaning:"Đến khi chúng tôi tới, chuyến bay đã rời đi rồi."},{correct:"By the time she got to customs, her luggage had arrived.",meaning:"Đến khi cô ấy ra hải quan, hành lý của cô ấy đã đến rồi."},{correct:"By the time the plane landed, it had stopped raining.",meaning:"Đến khi máy bay hạ cánh, trời đã tạnh mưa."}]}},
  {lesson:13,content:{title:"3. How long does it take to...?",desc:"Mẫu câu hỏi về thời gian cần để thực hiện một việc/hành trình.",formula:[{text:"How long does it take to + V?",classes:"bg-teal-100 text-teal-700 border-teal-300 font-bold"}],practiceList:[{correct:"How long does it take to check in?",meaning:"Làm thủ tục check-in mất bao lâu?"},{correct:"It takes about two hours to go through customs.",meaning:"Việc qua hải quan mất khoảng hai giờ."},{correct:"How long does the flight take?",meaning:"Chuyến bay mất bao lâu?"}]}},

  // ===== BÀI 15 (lesson 14) — Phương tiện & đường xá =====
  {lesson:14,content:{title:"1. Past Perfect giới thiệu",desc:"Dùng để diễn tả một hành động xảy ra và kết thúc TRƯỚC một hành động khác trong quá khứ.",formula:[{text:"S + had + V(p.p)/V-ed",classes:"bg-orange-100 text-orange-700 border-orange-300 font-bold"}],practiceList:[{correct:"When I arrived, the bus had already left.",meaning:"Khi tôi đến, xe buýt đã rời đi rồi."},{correct:"She had finished driving before it started to rain.",meaning:"Cô ấy đã lái xe xong trước khi trời bắt đầu mưa."},{correct:"They had reached the harbour by 9 o'clock.",meaning:"Họ đã đến bến tàu trước 9 giờ."}]}},
  {lesson:14,content:{title:"2. Get on/off vs Get into/out of",desc:"'Get on/off' dùng cho phương tiện lớn (có thể đứng, đi lại được). 'Get into/out of' dùng cho phương tiện nhỏ (ô tô, taxi).",formula:[{text:"get on/off + bus/coach/tram",classes:"bg-blue-100 text-blue-700 border-blue-300 font-bold"},{text:"get into/out of + car/taxi",classes:"bg-green-100 text-green-700 border-green-300 font-bold"}],practiceList:[{correct:"We got on the tram at the petrol station.",meaning:"Chúng tôi lên xe điện ở trạm xăng."},{correct:"He got off the coach near the roundabout.",meaning:"Anh ấy xuống xe khách gần bùng binh."},{correct:"She got into the lorry to help the driver.",meaning:"Cô ấy lên xe tải để giúp người lái xe."}]}},
  {lesson:14,content:{title:"3. Các cụm từ chỉ đường",desc:"Sử dụng câu mệnh lệnh và các giới từ để hướng dẫn đường đi.",formula:[{text:"Turn left/right at + địa điểm",classes:"bg-purple-100 text-purple-700 border-purple-300 font-bold"},{text:"Go past + địa điểm",classes:"bg-pink-100 text-pink-700 border-pink-300 font-bold"}],practiceList:[{correct:"Turn left at the roundabout.",meaning:"Rẽ trái ở bùng binh."},{correct:"Go past the petrol station and you'll see the port.",meaning:"Đi qua trạm xăng thì bạn sẽ thấy bến cảng."},{correct:"You pass the crossing, then turn right.",meaning:"Bạn đi qua chỗ băng qua đường, rồi rẽ phải."}]}},

  // ===== BÀI 16 (lesson 15) — Khách sạn & chỗ ở =====
  {lesson:15,content:{title:"1. Past Perfect ôn tập",desc:"Ôn lại Quá khứ hoàn thành trong ngữ cảnh đặt phòng và lưu trú khách sạn.",formula:[{text:"S + had + already + V(p.p)",classes:"bg-yellow-100 text-yellow-700 border-yellow-300 font-bold"}],practiceList:[{correct:"The room had already been booked when we arrived.",meaning:"Phòng đã được đặt trước khi chúng tôi đến."},{correct:"She had checked out before we got to the hotel.",meaning:"Cô ấy đã trả phòng trước khi chúng tôi đến khách sạn."},{correct:"They hadn't made a reservation, so the hotel was full.",meaning:"Họ chưa đặt phòng trước, nên khách sạn đã hết phòng."}]}},
  {lesson:15,content:{title:"2. Make a reservation / Book a room",desc:"Các cụm động từ thực tế dùng khi đặt phòng khách sạn.",formula:[{text:"make a reservation / book a room",classes:"bg-indigo-100 text-indigo-700 border-indigo-300 font-bold"}],practiceList:[{correct:"I'd like to make a reservation for two nights.",meaning:"Tôi muốn đặt phòng trong hai đêm."},{correct:"We booked a double room online.",meaning:"Chúng tôi đã đặt một phòng đôi qua mạng."},{correct:"Can the receptionist book a single room for me?",meaning:"Lễ tân có thể đặt một phòng đơn cho tôi không?"}]}},
  {lesson:15,content:{title:"3. Is there a...? / Does the hotel have...?",desc:"Mẫu câu hỏi về tiện nghi của khách sạn.",formula:[{text:"Is there a + tiện nghi?",classes:"bg-teal-100 text-teal-700 border-teal-300 font-bold"},{text:"Does the hotel have + tiện nghi?",classes:"bg-orange-100 text-orange-700 border-orange-300 font-bold"}],practiceList:[{correct:"Is there a guidebook at the reception?",meaning:"Có sách hướng dẫn ở quầy lễ tân không?"},{correct:"Does the hotel have a sightseeing tour?",meaning:"Khách sạn có tour tham quan không?"},{correct:"Is there a single room available tonight?",meaning:"Tối nay có phòng đơn nào trống không?"}]}},

  // ===== BÀI 17 (lesson 16) — Công việc & nghề nghiệp mở rộng =====
  {lesson:16,content:{title:"1. Cấu trúc Work as",desc:"Dùng để giới thiệu nghề nghiệp của ai đó (Làm việc với tư cách là...).",formula:[{text:"S + work/works + as + a/an + nghề nghiệp",classes:"bg-pink-100 text-pink-700 border-pink-300 font-bold"}],practiceList:[{correct:"She works as a secretary.",meaning:"Cô ấy làm nghề thư ký."},{correct:"My brother works as a chef in a restaurant.",meaning:"Anh trai tôi làm đầu bếp trong một nhà hàng."},{correct:"I hope to work as a scientist one day.",meaning:"Tôi hy vọng một ngày nào đó sẽ làm nhà khoa học."}]}},
  {lesson:16,content:{title:"2. Cấu trúc Be responsible for",desc:"Dùng để nói về trách nhiệm, nhiệm vụ chính yếu trong công việc.",formula:[{text:"S + be + responsible for + V-ing/N",classes:"bg-yellow-100 text-yellow-700 border-yellow-300 font-bold"}],practiceList:[{correct:"He is responsible for managing the team.",meaning:"Anh ấy chịu trách nhiệm quản lý nhóm."},{correct:"The cleaner is responsible for keeping the office clean.",meaning:"Người dọn dẹp có trách nhiệm giữ văn phòng sạch sẽ."},{correct:"Are you responsible for this project?",meaning:"Bạn có chịu trách nhiệm cho dự án này không?"}]}},
  {lesson:16,content:{title:"3. Mệnh đề quan hệ Who/Which (Nghề nghiệp)",desc:"Dùng để giải thích, định nghĩa một công việc hoặc một vật dụng liên quan.",formula:[{text:"A/An (Nghề) is a person who + V",classes:"bg-blue-100 text-blue-700 border-blue-300 font-bold"},{text:"A/An (Vật) is a thing which + V",classes:"bg-green-100 text-green-700 border-green-300 font-bold"}],practiceList:[{correct:"A scientist is a person who does research.",meaning:"Nhà khoa học là người làm công tác nghiên cứu."},{correct:"An assistant is someone who helps the boss.",meaning:"Trợ lý là người giúp việc cho sếp."},{correct:"A scanner is a machine which copies documents.",meaning:"Máy quét là loại máy sao chép tài liệu."}]}},

  // ===== BÀI 18 (lesson 17) — Môi trường làm việc =====
  {lesson:17,content:{title:"1. Reported Questions",desc:"Tường thuật lại câu hỏi của người khác, dùng 'if/whether' cho câu hỏi Yes/No và giữ từ hỏi cho câu hỏi Wh-.",formula:[{text:"S + asked + (if/whether) + S + V",classes:"bg-purple-100 text-purple-700 border-purple-300 font-bold"}],practiceList:[{correct:"She asked me where I worked.",meaning:"Cô ấy hỏi tôi làm việc ở đâu."},{correct:"He asked if I had experience.",meaning:"Anh ấy hỏi liệu tôi có kinh nghiệm không."},{correct:"They asked whether I could start next week.",meaning:"Họ hỏi liệu tôi có thể bắt đầu vào tuần tới không."}]}},
  {lesson:17,content:{title:"2. Have to / Don't have to",desc:"Ôn 'have to' để nói về sự bắt buộc trong công việc, và 'don't have to' khi không cần thiết phải làm gì.",formula:[{text:"S + have/has to + V (bắt buộc)",classes:"bg-pink-100 text-pink-700 border-pink-300 font-bold"},{text:"S + don't/doesn't have to + V (không cần)",classes:"bg-yellow-100 text-yellow-700 border-yellow-300 font-bold"}],practiceList:[{correct:"You have to attend the meeting.",meaning:"Bạn phải tham dự cuộc họp."},{correct:"She doesn't have to work on Saturdays.",meaning:"Cô ấy không cần phải làm việc vào các ngày thứ Bảy."},{correct:"Do I have to bring my qualification certificate?",meaning:"Tôi có cần phải mang giấy chứng nhận trình độ không?"}]}},
  {lesson:17,content:{title:"3. Fill in an application form",desc:"Tình huống xin việc — điền đơn ứng tuyển.",formula:[{text:"fill in an application form",classes:"bg-indigo-100 text-indigo-700 border-indigo-300 font-bold"}],practiceList:[{correct:"Please fill in the application form before the interview.",meaning:"Vui lòng điền đơn ứng tuyển trước buổi phỏng vấn."},{correct:"I filled in my qualifications on the form.",meaning:"Tôi đã điền trình độ của mình vào đơn."},{correct:"Has she applied for the job yet?",meaning:"Cô ấy đã ứng tuyển cho công việc đó chưa?"}]}},
  // ===== BÀI 19 (lesson 18) — Công nghệ & truyền thông =====
  {lesson:18,content:{title:"1. Have been + V-ing (sơ cấp)",desc:"Hiện tại hoàn thành tiếp diễn dùng để nhấn mạnh quá trình của một hành động đã bắt đầu trong quá khứ và vẫn đang tiếp diễn ở hiện tại.",formula:[{text:"S + have/has + been + V-ing",classes:"bg-teal-100 text-teal-700 border-teal-300 font-bold"}],practiceList:[{correct:"I've been using this app for 2 years.",meaning:"Tôi đã sử dụng ứng dụng này trong 2 năm rồi."},{correct:"She has been chatting online all morning.",meaning:"Cô ấy đã nhắn tin trực tuyến suốt cả buổi sáng."},{correct:"They have been downloading the file for an hour.",meaning:"Họ đã tải file này trong một giờ rồi."}]}},
  {lesson:18,content:{title:"2. Post / Share / Follow",desc:"Các động từ phổ biến khi sử dụng internet, mạng xã hội.",formula:[{text:"post (đăng tải)/share (chia sẻ)/follow (theo dõi)",classes:"bg-orange-100 text-orange-700 border-orange-300 font-bold"}],practiceList:[{correct:"She posted a selfie on social media.",meaning:"Cô ấy đã đăng một bức ảnh tự chụp lên mạng xã hội."},{correct:"Can you share this blog with me?",meaning:"Bạn có thể chia sẻ bài blog này cho tôi không?"},{correct:"I follow my favourite singer on social media.",meaning:"Tôi theo dõi ca sĩ yêu thích của tôi trên mạng xã hội."}]}},
  {lesson:18,content:{title:"3. Can I / Could I / May I",desc:"Mẫu câu lịch sự để xin phép sử dụng đồ vật/thiết bị của người khác.",formula:[{text:"Can/Could/May I + V(nguyên thể)?",classes:"bg-blue-100 text-blue-700 border-blue-300 font-bold"}],practiceList:[{correct:"Can I use your keyboard?",meaning:"Tôi có thể dùng bàn phím của bạn không?"},{correct:"Could I borrow your password for a minute?",meaning:"Tôi có thể mượn mật khẩu của bạn một chút không?"},{correct:"May I check my chatroom messages?",meaning:"Tôi có thể kiểm tra tin nhắn trong phòng chat không?"}]}},

  // ===== BÀI 20 (lesson 19) — Thiết bị & máy móc =====
  {lesson:19,content:{title:"1. Passive mở rộng",desc:"Dùng câu bị động để nói về quy trình tự động của thiết bị công nghệ.",formula:[{text:"N + is/are + V(p.p)",classes:"bg-green-100 text-green-700 border-green-300 font-bold"}],practiceList:[{correct:"Photos are stored on the cloud.",meaning:"Hình ảnh được lưu trữ trên đám mây."},{correct:"Messages are sent automatically.",meaning:"Tin nhắn được gửi tự động."},{correct:"The screen is cleaned with a soft cloth.",meaning:"Màn hình được lau bằng một miếng vải mềm."}]}},
  {lesson:19,content:{title:"2. How does it work?",desc:"Mẫu câu hỏi cách sử dụng/hoạt động của thiết bị.",formula:[{text:"How does + thiết bị + work?",classes:"bg-purple-100 text-purple-700 border-purple-300 font-bold"}],practiceList:[{correct:"How does this printer work?",meaning:"Cái máy in này hoạt động như thế nào?"},{correct:"How does the microphone connect to the PC?",meaning:"Cái micro kết nối với máy tính như thế nào?"},{correct:"I don't know how the DVD player works.",meaning:"Tôi không biết cái đầu DVD hoạt động như thế nào."}]}},
  {lesson:19,content:{title:"3. Turn on/off/up/down",desc:"Các cụm động từ thông dụng khi điều khiển thiết bị điện tử.",formula:[{text:"turn on/off + thiết bị",classes:"bg-pink-100 text-pink-700 border-pink-300 font-bold"},{text:"turn up/down + âm lượng",classes:"bg-yellow-100 text-yellow-700 border-yellow-300 font-bold"}],practiceList:[{correct:"Please turn on the CD player.",meaning:"Vui lòng mở đầu CD."},{correct:"Can you turn down the microphone?",meaning:"Bạn có thể giảm âm lượng micro xuống không?"},{correct:"Turn off the screen before you leave.",meaning:"Hãy tắt màn hình trước khi bạn ra ngoài."}]}},

  // ===== BÀI 21 (lesson 20) — Âm nhạc & nghệ thuật =====
  {lesson:20,content:{title:"1. Verb + gerund vs infinitive",desc:"Một số động từ theo sau bắt buộc phải dùng V-ing (gerund) hoặc To-V (infinitive).",formula:[{text:"enjoy/finish/suggest + V-ing",classes:"bg-blue-100 text-blue-700 border-blue-300 font-bold"},{text:"decide/hope/want + to V",classes:"bg-indigo-100 text-indigo-700 border-indigo-300 font-bold"}],practiceList:[{correct:"I enjoy listening to jazz.",meaning:"Tôi thích nghe nhạc jazz."},{correct:"She decided to go to the art gallery.",meaning:"Cô ấy đã quyết định đến phòng trưng bày nghệ thuật."},{correct:"He suggested visiting the exhibition.",meaning:"Anh ấy đề xuất đi tham quan triển lãm."}]}},
  {lesson:20,content:{title:"2. Have been to + place",desc:"Ôn tập cấu trúc Hiện tại hoàn thành với 'ever/never' để hỏi/đáp về kinh nghiệm du lịch, tham quan.",formula:[{text:"Have/Has + S + ever + been to + nơi chốn?",classes:"bg-teal-100 text-teal-700 border-teal-300 font-bold"}],practiceList:[{correct:"Have you ever been to an opera?",meaning:"Bạn đã từng đi xem opera chưa?"},{correct:"She has never been to a music festival.",meaning:"Cô ấy chưa từng đi xem lễ hội âm nhạc nào."},{correct:"We have been to that gallery twice.",meaning:"Chúng tôi đã đến phòng trưng bày đó hai lần."}]}},
  {lesson:20,content:{title:"3. What kind of...?",desc:"Mẫu câu để hỏi chi tiết hơn về thể loại yêu thích (nhạc, phim, sách).",formula:[{text:"What kind of + N + do you like?",classes:"bg-orange-100 text-orange-700 border-orange-300 font-bold"}],practiceList:[{correct:"What kind of music do you like?",meaning:"Bạn thích loại nhạc nào?"},{correct:"What kind of band is your favourite?",meaning:"Ban nhạc kiểu nào là yêu thích của bạn?"},{correct:"I like hip hop and rap.",meaning:"Tôi thích nhạc hip hop và rap."}]}},

  // ===== BÀI 22 (lesson 21) — Phim & truyền thông =====
  {lesson:21,content:{title:"1. Think (that) ...",desc:"Diễn đạt ý kiến cá nhân về phim/chương trình.",formula:[{text:"I think (that) + clause",classes:"bg-pink-100 text-pink-700 border-pink-300 font-bold"}],practiceList:[{correct:"I think that the action film is exciting.",meaning:"Tôi nghĩ rằng bộ phim hành động đó rất thú vị."},{correct:"She thinks the comedy is funny.",meaning:"Cô ấy nghĩ bộ phim hài đó rất hài hước."},{correct:"Do you think the review is fair?",meaning:"Bạn có nghĩ bài đánh giá đó là công bằng không?"}]}},
  {lesson:21,content:{title:"2. Be on",desc:"Dùng 'be on' để nói một bộ phim/chương trình đang được chiếu/phát sóng.",formula:[{text:"N + be + on",classes:"bg-yellow-100 text-yellow-700 border-yellow-300 font-bold"}],practiceList:[{correct:"The film is on at the cinema.",meaning:"Bộ phim đang được chiếu tại rạp."},{correct:"What's on TV tonight?",meaning:"Tối nay có gì trên TV?"},{correct:"A new horror programme is on this channel.",meaning:"Một chương trình kinh dị mới đang phát trên kênh này."}]}},
  {lesson:21,content:{title:"3. Recommend/Suggest + V-ing",desc:"Ôn cấu trúc gợi ý xem một bộ phim hoặc sự kiện nào đó.",formula:[{text:"recommend/suggest + V-ing",classes:"bg-indigo-100 text-indigo-700 border-indigo-300 font-bold"}],practiceList:[{correct:"I recommend watching this character's performance.",meaning:"Tôi gợi ý nên xem màn trình diễn của nhân vật này."},{correct:"She suggested going to the event together.",meaning:"Cô ấy gợi ý nên cùng nhau đi đến sự kiện."},{correct:"He recommends reading the article first.",meaning:"Anh ấy gợi ý nên đọc bài báo trước."}]}},

  // ===== BÀI 23 (lesson 22) — Môi trường & thiên nhiên =====
  {lesson:22,content:{title:"1. Should trong lời kêu gọi môi trường",desc:"Sử dụng 'should' để kêu gọi và khuyên bảo hành động vì lợi ích môi trường.",formula:[{text:"We/People + should + V(nguyên thể)",classes:"bg-teal-100 text-teal-700 border-teal-300 font-bold"}],practiceList:[{correct:"We should recycle more.",meaning:"Chúng ta nên tái chế nhiều hơn."},{correct:"People should protect wildlife in the rainforest.",meaning:"Mọi người nên bảo vệ động vật hoang dã trong rừng nhiệt đới."},{correct:"You shouldn't pollute the coast.",meaning:"Bạn không nên làm ô nhiễm bờ biển."}]}},
  {lesson:22,content:{title:"2. Conditional 1: If ... will ...",desc:"Ôn câu điều kiện loại 1, dùng để nói về điều kiện có thể xảy ra ở hiện tại/tương lai.",formula:[{text:"If + S + V(HTĐ), S + will + V",classes:"bg-orange-100 text-orange-700 border-orange-300 font-bold"}],practiceList:[{correct:"If we don't act, the environment will be damaged.",meaning:"Nếu chúng ta không hành động, môi trường sẽ bị tổn hại."},{correct:"If you recycle, you will help nature.",meaning:"Nếu bạn tái chế, bạn sẽ giúp ích cho thiên nhiên."},{correct:"The climate will change if pollution increases.",meaning:"Khí hậu sẽ thay đổi nếu ô nhiễm gia tăng."}]}},
  {lesson:22,content:{title:"3. Be made from vs Be made of",desc:"'Be made of' dùng cho vật liệu có thể thấy rõ, không đổi tính chất. 'Be made from' dùng cho nguyên liệu gốc đã biến đổi hoàn toàn.",formula:[{text:"be made of (vật liệu rõ, ví dụ: gỗ thành bàn)",classes:"bg-blue-100 text-blue-700 border-blue-300 font-bold"},{text:"be made from (nguyên liệu đã biến đổi, ví dụ: nho thành rượu)",classes:"bg-purple-100 text-purple-700 border-purple-300 font-bold"}],practiceList:[{correct:"This table is made of wood.",meaning:"Cái bàn này được làm từ gỗ."},{correct:"Paper is made from trees.",meaning:"Giấy được làm từ cây."},{correct:"Plastic bottles are bad for the environment.",meaning:"Chai nhựa không tốt cho môi trường."}]}},

  // ===== BÀI 24 (lesson 23) — Nơi chốn & tòa nhà mở rộng =====
  {lesson:23,content:{title:"1. Used to (mở rộng)",desc:"Dùng 'used to' để nói về một thói quen/tình trạng trong quá khứ nhưng không còn đúng ở hiện tại.",formula:[{text:"S + used to + V(nguyên thể)",classes:"bg-pink-100 text-pink-700 border-pink-300 font-bold"}],practiceList:[{correct:"This factory used to make cars.",meaning:"Nhà máy này trước đây từng sản xuất ô tô."},{correct:"There used to be a castle near the coast.",meaning:"Trước đây có một tòa lâu đài gần bờ biển."},{correct:"The cathedral didn't use to be this big.",meaning:"Trước đây nhà thờ lớn này không to như vậy."}]}},
  {lesson:23,content:{title:"2. Passive Past",desc:"Ôn câu bị động ở quá khứ để nói về thời gian xây dựng các công trình.",formula:[{text:"N + was/were + built/founded + (in + năm)",classes:"bg-yellow-100 text-yellow-700 border-yellow-300 font-bold"}],practiceList:[{correct:"The cathedral was built in the 12th century.",meaning:"Nhà thờ lớn này được xây vào thế kỷ 12."},{correct:"This stadium was built five years ago.",meaning:"Sân vận động này được xây dựng năm năm trước."},{correct:"The campsite was opened last summer.",meaning:"Khu cắm trại này đã được mở vào mùa hè năm ngoái."}]}},
  {lesson:23,content:{title:"3. How far is it from...to...?",desc:"Mẫu câu hỏi khoảng cách giữa hai địa điểm.",formula:[{text:"How far is it from + A + to + B?",classes:"bg-green-100 text-green-700 border-green-300 font-bold"}],practiceList:[{correct:"How far is it from the harbour to the stadium?",meaning:"Khoảng cách từ bến cảng đến sân vận động là bao xa?"},{correct:"It's about ten kilometres from the farm to the gallery.",meaning:"Từ trang trại đến phòng trưng bày khoảng mười ki-lô-mét."},{correct:"How far is the campsite from the coast?",meaning:"Khu cắm trại cách bờ biển bao xa?"}]}},
  // ===== BÀI 25 (lesson 24) — Thì & Modal Verbs ôn tổng hợp =====
  {lesson:24,content:{title:"1. Although / However / Despite",desc:"Các liên từ/trạng từ tương phản ở cấp A2+, dùng để nối hai ý đối lập.",formula:[{text:"Although + clause, clause",classes:"bg-blue-100 text-blue-700 border-blue-300 font-bold"},{text:"despite + N/V-ing",classes:"bg-purple-100 text-purple-700 border-purple-300 font-bold"}],practiceList:[{correct:"Although it was raining, we went out.",meaning:"Mặc dù trời đang mưa, chúng tôi vẫn đi ra ngoài."},{correct:"However, the test was nearly impossible.",meaning:"Tuy nhiên, bài kiểm tra gần như là không thể làm được."},{correct:"Despite the delay, we arrived on time.",meaning:"Mặc dù bị trễ, chúng tôi vẫn đến đúng giờ."}]}},
  {lesson:24,content:{title:"2. Ôn tổng hợp Modal Verbs",desc:"Ôn lại toàn bộ động từ khuyết thiếu thông dụng ở cấp KET.",formula:[{text:"can/could/must/should/may/might/will/would/shall + V",classes:"bg-pink-100 text-pink-700 border-pink-300 font-bold"}],practiceList:[{correct:"You must finish this immediately.",meaning:"Bạn phải hoàn thành cái này ngay lập tức."},{correct:"She might come to the party.",meaning:"Cô ấy có thể sẽ đến buổi tiệc."},{correct:"We should probably leave now.",meaning:"Chúng ta nên rời đi ngay bây giờ."}]}},
  {lesson:24,content:{title:"3. Trạng từ mức độ trong câu phức",desc:"Ôn các trạng từ mức độ thường gặp trong câu phức ở trình độ A2.",formula:[{text:"quite/nearly/almost/certainly/probably + adj/V",classes:"bg-yellow-100 text-yellow-700 border-yellow-300 font-bold"}],practiceList:[{correct:"I'm nearly finished with my homework.",meaning:"Tôi gần như đã hoàn thành xong bài tập về nhà."},{correct:"She is certainly the best student in class.",meaning:"Cô ấy chắc chắn là học sinh giỏi nhất trong lớp."},{correct:"It will probably rain this afternoon.",meaning:"Chiều nay có thể sẽ mưa."}]}},

  // ===== BÀI 26 (lesson 25) — Reported Speech =====
  {lesson:25,content:{title:"1. Reported Speech ôn tổng hợp",desc:"Ôn lại các dạng câu tường thuật: 'say/tell + that', 'ask + if/whether', 'ask + wh-'.",formula:[{text:"S + said/told + (that) + clause",classes:"bg-indigo-100 text-indigo-700 border-indigo-300 font-bold"},{text:"S + asked + if/whether/wh- + clause",classes:"bg-teal-100 text-teal-700 border-teal-300 font-bold"}],practiceList:[{correct:"He said (that) he was tired.",meaning:"Anh ấy nói rằng anh ấy mệt."},{correct:"She told me she had finished her homework.",meaning:"Cô ấy nói với tôi rằng cô ấy đã làm xong bài tập."},{correct:"They asked if I wanted to come.",meaning:"Họ hỏi liệu tôi có muốn đến không."}]}},
  {lesson:25,content:{title:"2. Backshift thì",desc:"Khi tường thuật, động từ thường phải lùi một thì so với câu trực tiếp (hiện tại → quá khứ).",formula:[{text:"\"am/is/are\" → was/were",classes:"bg-orange-100 text-orange-700 border-orange-300 font-bold"},{text:"\"will\" → would",classes:"bg-blue-100 text-blue-700 border-blue-300 font-bold"}],practiceList:[{correct:"\"I am tired.\" → She said she was tired.",meaning:"\"Tôi mệt.\" → Cô ấy nói rằng cô ấy mệt."},{correct:"\"I will call you.\" → He said he would call me.",meaning:"\"Tôi sẽ gọi cho bạn.\" → Anh ấy nói rằng anh ấy sẽ gọi cho tôi."},{correct:"\"I can swim.\" → She said she could swim.",meaning:"\"Tôi có thể bơi.\" → Cô ấy nói rằng cô ấy có thể bơi."}]}},
  {lesson:25,content:{title:"3. Reported Commands",desc:"Tường thuật câu mệnh lệnh dùng 'told to' (bảo làm gì) hoặc 'told not to/asked not to' (bảo không làm gì).",formula:[{text:"S + told/asked + O + (not) + to V",classes:"bg-green-100 text-green-700 border-green-300 font-bold"}],practiceList:[{correct:"He told me to wait.",meaning:"Anh ấy bảo tôi chờ."},{correct:"She asked me not to be late.",meaning:"Cô ấy nhờ tôi đừng trễ."},{correct:"The teacher told us to be quiet.",meaning:"Giáo viên bảo chúng tôi im lặng."}]}},

  // ===== BÀI 27 (lesson 26) — Câu điều kiện =====
  {lesson:26,content:{title:"1. Conditional 2 giới thiệu",desc:"Câu điều kiện loại 2 dùng để nói về một điều kiện không có thật ở hiện tại và kết quả giả định của nó.",formula:[{text:"If + S + V(qkđ), S + would + V",classes:"bg-purple-100 text-purple-700 border-purple-300 font-bold"}],practiceList:[{correct:"If I had more money, I would travel the world.",meaning:"Nếu tôi có nhiều tiền hơn, tôi sẽ đi du lịch khắp thế giới."},{correct:"If she succeeded, she would celebrate.",meaning:"Nếu cô ấy thành công, cô ấy sẽ ăn mừng."},{correct:"I would help you if I had the chance.",meaning:"Tôi sẽ giúp bạn nếu tôi có cơ hội."}]}},
  {lesson:26,content:{title:"2. Phân biệt Conditional 1 vs 2",desc:"Loại 1 nói về điều có thể xảy ra thật, loại 2 nói về điều không có thật/giả định.",formula:[{text:"If it rains, ... (có thể xảy ra)",classes:"bg-pink-100 text-pink-700 border-pink-300 font-bold"},{text:"If I were rich, ... (không có thật)",classes:"bg-yellow-100 text-yellow-700 border-yellow-300 font-bold"}],practiceList:[{correct:"If it rains, I will stay home.",meaning:"Nếu trời mưa, tôi sẽ ở nhà."},{correct:"If I were rich, I would buy a big house.",meaning:"Nếu tôi giàu, tôi sẽ mua một căn nhà lớn."},{correct:"I would avoid that mistake if I had another chance.",meaning:"Tôi sẽ tránh sai lầm đó nếu tôi có một cơ hội khác."}]}},
  {lesson:26,content:{title:"3. Unless = If ... not",desc:"'Unless' mang nghĩa phủ định của điều kiện, tương đương 'if...not'.",formula:[{text:"Unless + S + V (= If + S + don't/doesn't + V)",classes:"bg-indigo-100 text-indigo-700 border-indigo-300 font-bold"}],practiceList:[{correct:"I'll go unless it rains.",meaning:"Tôi sẽ đi trừ khi trời mưa."},{correct:"Unless you hurry, you will fail.",meaning:"Trừ khi bạn nhanh lên, bạn sẽ thất bại."},{correct:"We won't succeed unless we try harder.",meaning:"Chúng ta sẽ không thành công trừ khi chúng ta cố gắng hơn."}]}},

  // ===== BÀI 28 (lesson 27) — Câu bị động ôn tổng hợp =====
  {lesson:27,content:{title:"1. Passive Present vs Past tổng hợp",desc:"Ôn lại câu bị động ở cả hai thì Hiện tại đơn và Quá khứ đơn.",formula:[{text:"is/are made/delivered (hiện tại)",classes:"bg-teal-100 text-teal-700 border-teal-300 font-bold"},{text:"was/were built/discovered (quá khứ)",classes:"bg-orange-100 text-orange-700 border-orange-300 font-bold"}],practiceList:[{correct:"This phone is made in Vietnam.",meaning:"Chiếc điện thoại này được sản xuất ở Việt Nam."},{correct:"The parcel was delivered yesterday.",meaning:"Bưu phẩm đã được giao hôm qua."},{correct:"Penicillin was discovered in 1928.",meaning:"Penicillin được phát hiện vào năm 1928."}]}},
  {lesson:27,content:{title:"2. By + Agent",desc:"Dùng 'by + người/vật thực hiện' khi cần nêu rõ ai đã làm hành động trong câu bị động.",formula:[{text:"S + be + V(p.p) + by + agent",classes:"bg-blue-100 text-blue-700 border-blue-300 font-bold"}],practiceList:[{correct:"It was written by a famous author.",meaning:"Nó được viết bởi một tác giả nổi tiếng."},{correct:"The song was performed by the band.",meaning:"Bài hát được trình diễn bởi ban nhạc."},{correct:"This event was organised by the school.",meaning:"Sự kiện này được tổ chức bởi nhà trường."}]}},
  {lesson:27,content:{title:"3. Have something done (ôn)",desc:"Ôn lại cấu trúc nhờ/thuê người khác làm gì đó cho mình.",formula:[{text:"S + have/has + N + V(p.p)",classes:"bg-purple-100 text-purple-700 border-purple-300 font-bold"}],practiceList:[{correct:"I'm having my hair cut tomorrow.",meaning:"Ngày mai tôi sẽ đi cắt tóc (nhờ người cắt)."},{correct:"She had her photos printed at the shop.",meaning:"Cô ấy đã nhờ in ảnh của mình ở cửa hàng."},{correct:"We are having the car repaired this week.",meaning:"Tuần này chúng tôi đang nhờ sửa xe."}]}},

  // ===== BÀI 29 (lesson 28) — Cụm động từ (Phrasal Verbs) =====
  {lesson:28,content:{title:"1. Look forward to + V-ing",desc:"Giới từ 'to' trong cụm này luôn theo sau bởi động từ thêm đuôi -ing (gerund).",formula:[{text:"look forward to + V-ing",classes:"bg-pink-100 text-pink-700 border-pink-300 font-bold"}],practiceList:[{correct:"I look forward to seeing you again.",meaning:"Tôi mong được gặp lại bạn."},{correct:"She looks forward to celebrating her birthday.",meaning:"Cô ấy mong chờ được ăn mừng sinh nhật của mình."},{correct:"We look forward to hearing from you.",meaning:"Chúng tôi mong nhận được hồi âm từ bạn."}]}},
  {lesson:28,content:{title:"2. Give up / Take up + V-ing",desc:"'Give up' nghĩa là từ bỏ một thói quen, 'take up' nghĩa là bắt đầu một thói quen mới.",formula:[{text:"give up + V-ing (từ bỏ)",classes:"bg-yellow-100 text-yellow-700 border-yellow-300 font-bold"},{text:"take up + V-ing (bắt đầu)",classes:"bg-green-100 text-green-700 border-green-300 font-bold"}],practiceList:[{correct:"He gave up smoking last year.",meaning:"Anh ấy đã bỏ hút thuốc vào năm ngoái."},{correct:"She took up painting during the holiday.",meaning:"Cô ấy bắt đầu học vẽ trong kỳ nghỉ."},{correct:"I'm going to take up swimming this summer.",meaning:"Tôi sẽ bắt đầu tập bơi vào mùa hè này."}]}},
  {lesson:28,content:{title:"3. Phrasal Verbs tách được vs không tách được",desc:"Một số cụm động từ có thể tách rời tân ngữ ra giữa (separable), một số không thể (inseparable).",formula:[{text:"pick up + O / pick + O + up (tách được)",classes:"bg-indigo-100 text-indigo-700 border-indigo-300 font-bold"},{text:"look after + O (không tách được)",classes:"bg-teal-100 text-teal-700 border-teal-300 font-bold"}],practiceList:[{correct:"Can you pick up the keys? / Can you pick the keys up?",meaning:"Bạn nhặt giúp tôi cái chìa khóa được không?"},{correct:"She looks after her younger brother.",meaning:"Cô ấy chăm sóc em trai mình."},{correct:"We set off early in the morning.",meaning:"Chúng tôi xuất phát sớm vào buổi sáng."}]}},

  // ===== BÀI 30 (lesson 29) — Verb + infinitive / gerund =====
  {lesson:29,content:{title:"1. Verb + to-infinitive",desc:"Một số động từ luôn theo sau bởi 'to + V (nguyên thể)'.",formula:[{text:"manage/afford/refuse/agree/offer/decide/hope/expect + to V",classes:"bg-orange-100 text-orange-700 border-orange-300 font-bold"}],practiceList:[{correct:"I managed to finish the project on time.",meaning:"Tôi đã xoay sở hoàn thành dự án đúng hạn."},{correct:"She refused to give up.",meaning:"Cô ấy đã từ chối bỏ cuộc."},{correct:"We hope to succeed this time.",meaning:"Chúng tôi hy vọng sẽ thành công lần này."}]}},
  {lesson:29,content:{title:"2. Verb + gerund",desc:"Một số động từ luôn theo sau bởi V-ing (gerund).",formula:[{text:"avoid/enjoy/finish/suggest/consider/keep + V-ing",classes:"bg-blue-100 text-blue-700 border-blue-300 font-bold"}],practiceList:[{correct:"He avoided making the same mistake.",meaning:"Anh ấy đã tránh mắc lại sai lầm tương tự."},{correct:"She enjoys helping other people.",meaning:"Cô ấy thích giúp đỡ người khác."},{correct:"They keep practising every day.",meaning:"Họ tiếp tục luyện tập mỗi ngày."}]}},
  {lesson:29,content:{title:"3. Verb + cả hai (nghĩa khác nhau)",desc:"Một số động từ có thể theo sau bởi cả to-V và V-ing nhưng mang nghĩa khác nhau, ví dụ 'remember'.",formula:[{text:"remember to do (nhớ để làm - chưa làm)",classes:"bg-purple-100 text-purple-700 border-purple-300 font-bold"},{text:"remember doing (nhớ đã làm - đã làm rồi)",classes:"bg-pink-100 text-pink-700 border-pink-300 font-bold"}],practiceList:[{correct:"Remember to lock the door before you leave.",meaning:"Nhớ khóa cửa trước khi bạn ra ngoài."},{correct:"I remember meeting her last year.",meaning:"Tôi nhớ là đã gặp cô ấy năm ngoái."},{correct:"Did you remember to bring the documents?",meaning:"Bạn có nhớ mang theo tài liệu không?"}]}},
  // ===== BÀI 31 (lesson 30) — Câu hỏi đuôi & Từ nối =====
  {lesson:30,content:{title:"1. Question Tags ôn tổng hợp",desc:"Ôn lại câu hỏi đuôi với các trợ động từ và động từ khuyết thiếu khác nhau.",formula:[{text:"..., isn't it?/don't they?/haven't you?/will you?",classes:"bg-yellow-100 text-yellow-700 border-yellow-300 font-bold"}],practiceList:[{correct:"It's a nice day, isn't it?",meaning:"Hôm nay là một ngày đẹp trời, đúng không?"},{correct:"They live near here, don't they?",meaning:"Họ sống gần đây, đúng không?"},{correct:"Close the door, will you?",meaning:"Đóng cửa lại được không?"}]}},
  {lesson:30,content:{title:"2. Từ nối văn viết",desc:"Các từ nối thường gặp trong email, tin nhắn ở trình độ A2.",formula:[{text:"however/therefore/moreover/besides",classes:"bg-indigo-100 text-indigo-700 border-indigo-300 font-bold"}],practiceList:[{correct:"I was tired; however, I finished my homework.",meaning:"Tôi mệt; tuy nhiên, tôi vẫn hoàn thành bài tập."},{correct:"It was raining, therefore we stayed home.",meaning:"Trời đang mưa, vì vậy chúng tôi đã ở nhà."},{correct:"She is smart. Besides, she is very hard-working.",meaning:"Cô ấy thông minh. Hơn nữa, cô ấy còn rất chăm chỉ."}]}},
  {lesson:30,content:{title:"3. So vs Because vs Although",desc:"Phân biệt 'so' (kết quả), 'because' (nguyên nhân), 'although' (tương phản).",formula:[{text:"clause + so + kết quả",classes:"bg-teal-100 text-teal-700 border-teal-300 font-bold"},{text:"clause + because + nguyên nhân",classes:"bg-orange-100 text-orange-700 border-orange-300 font-bold"}],practiceList:[{correct:"It was raining, so we stayed inside.",meaning:"Trời đang mưa, vì vậy chúng tôi ở trong nhà."},{correct:"I stayed home because I was sick.",meaning:"Tôi đã ở nhà vì tôi bị bệnh."},{correct:"Although it was cold, she went swimming.",meaning:"Mặc dù trời lạnh, cô ấy vẫn đi bơi."}]}},

  // ===== BÀI 32 (lesson 31) — Kỹ năng đọc hiểu: Biển hiệu & Thông báo =====
  {lesson:31,content:{title:"1. Imperative trong biển hiệu",desc:"Cách ra lệnh, yêu cầu thường gặp trên các biển báo, hướng dẫn công cộng.",formula:[{text:"Do not + V / No + V-ing",classes:"bg-red-100 text-red-700 border-red-300 font-bold"}],practiceList:[{correct:"No parking.",meaning:"Không đỗ xe."},{correct:"Please switch off your phone.",meaning:"Vui lòng tắt điện thoại của bạn."},{correct:"Do not enter.",meaning:"Không được vào."}]}},
  {lesson:31,content:{title:"2. Passive trong thông báo",desc:"Sử dụng câu bị động để diễn tả những điều cấm/được phép mang tính quy định chung.",formula:[{text:"S + be + permitted/allowed/kept + (by/on...)",classes:"bg-blue-100 text-blue-700 border-blue-300 font-bold"}],practiceList:[{correct:"Entry is not permitted after 9 p.m.",meaning:"Không được phép vào sau 9 giờ tối."},{correct:"Dogs must be kept on leads.",meaning:"Chó phải được giữ bằng dây xích."},{correct:"Photos are not allowed in the museum.",meaning:"Không được phép chụp ảnh trong viện bảo tàng."}]}},
  {lesson:31,content:{title:"3. Modal trong biển hiệu",desc:"Dùng 'must' (bắt buộc), 'may not' (không được phép) trên các biển thông báo.",formula:[{text:"Passengers/Visitors + must/may not + V",classes:"bg-purple-100 text-purple-700 border-purple-300 font-bold"}],practiceList:[{correct:"Passengers must present their tickets.",meaning:"Hành khách phải xuất trình vé của mình."},{correct:"Visitors may not feed the animals.",meaning:"Khách thăm quan không được cho động vật ăn."},{correct:"You must wear a seatbelt.",meaning:"Bạn phải đeo dây an toàn."}]}},

  // ===== BÀI 33 (lesson 32) — Kỹ năng viết: Email & Tin nhắn =====
  {lesson:32,content:{title:"1. Cấu trúc Email A2",desc:"Các mẫu câu mở đầu và kết thúc tiêu chuẩn khi viết thư hay email ngắn.",formula:[{text:"Dear/Hi + Tên,",classes:"bg-pink-100 text-pink-700 border-pink-300 font-bold"},{text:"Hope to hear from you soon.",classes:"bg-yellow-100 text-yellow-700 border-yellow-300 font-bold"}],practiceList:[{correct:"Hi Anna, Thanks for your email.",meaning:"Chào Anna, Cảm ơn email của bạn."},{correct:"I'm writing to invite you to my party.",meaning:"Tôi viết thư này để mời bạn đến buổi tiệc của tôi."},{correct:"Hope to hear from you soon. Best wishes, Tom.",meaning:"Mong sớm nhận được hồi âm từ bạn. Chúc bạn mọi điều tốt đẹp, Tom."}]}},
  {lesson:32,content:{title:"2. Mời và từ chối lịch sự",desc:"Mẫu câu dùng để rủ rê ai đó đi chơi và cách từ chối khéo léo trong văn viết.",formula:[{text:"Would you like to + V?",classes:"bg-green-100 text-green-700 border-green-300 font-bold"},{text:"I'm afraid I can't...",classes:"bg-indigo-100 text-indigo-700 border-indigo-300 font-bold"}],practiceList:[{correct:"Would you like to come to the cinema with me?",meaning:"Bạn có muốn đi xem phim cùng tôi không?"},{correct:"I'm afraid I can't make it this weekend.",meaning:"Tôi e là tôi không thể đến được vào cuối tuần này."},{correct:"Thanks for the invitation, but I'm busy.",meaning:"Cảm ơn lời mời, nhưng tôi đang bận."}]}},
  {lesson:32,content:{title:"3. Đưa ra lời đề xuất",desc:"Gợi ý các kế hoạch thay thế hoặc ý tưởng mới trong email/tin nhắn.",formula:[{text:"Why don't we + V(nguyên thể)?",classes:"bg-teal-100 text-teal-700 border-teal-300 font-bold"},{text:"How about/What about + V-ing?",classes:"bg-orange-100 text-orange-700 border-orange-300 font-bold"}],practiceList:[{correct:"Why don't we meet at the café?",meaning:"Sao chúng ta không gặp nhau ở quán cà phê nhé?"},{correct:"How about going to the gallery on Saturday?",meaning:"Đi đến phòng trưng bày vào thứ Bảy thì sao?"},{correct:"What about sending the form by email?",meaning:"Gửi mẫu đơn qua email thì sao?"}]}},

  // ===== BÀI 34 (lesson 33) — Kỹ năng nghe: Hội thoại thực tế =====
  {lesson:33,content:{title:"1. Lịch sự trong giao tiếp thực tế",desc:"Dùng các cụm từ mở đầu nhẹ nhàng khi phàn nàn, từ chối hay báo tin không vui.",formula:[{text:"I'm sorry, but... / I'm afraid...",classes:"bg-blue-100 text-blue-700 border-blue-300 font-bold"}],practiceList:[{correct:"I'm sorry, but this isn't what I ordered.",meaning:"Tôi xin lỗi, nhưng đây không phải món tôi đã đặt."},{correct:"I'm afraid the table is reserved.",meaning:"Tôi e là cái bàn này đã được đặt trước."},{correct:"I'm sorry, but I have to cancel.",meaning:"Tôi xin lỗi, nhưng tôi phải hủy."}]}},
  {lesson:33,content:{title:"2. Câu hỏi đuôi trong hội thoại",desc:"Dùng để kiểm tra thông tin hoặc khuyến khích người nghe đồng ý trong hội thoại thực tế.",formula:[{text:"..., isn't it?",classes:"bg-purple-100 text-purple-700 border-purple-300 font-bold"}],practiceList:[{correct:"It's a nice day, isn't it?",meaning:"Hôm nay là một ngày đẹp trời, đúng không?"},{correct:"You'd like to confirm the reservation, wouldn't you?",meaning:"Bạn muốn xác nhận đặt phòng, đúng không?"},{correct:"We agreed on the time, didn't we?",meaning:"Chúng ta đã đồng ý về thời gian rồi, đúng không?"}]}},
  {lesson:33,content:{title:"3. Giao tiếp qua điện thoại",desc:"Cấu trúc tiêu chuẩn khi nhấc máy, chuyển lời hoặc hứa gọi lại.",formula:[{text:"This is + Tên + speaking.",classes:"bg-pink-100 text-pink-700 border-pink-300 font-bold"},{text:"Can I take a message? / I'll call back.",classes:"bg-yellow-100 text-yellow-700 border-yellow-300 font-bold"}],practiceList:[{correct:"Hello, this is Tom speaking.",meaning:"Xin chào, đây là Tom đang nói."},{correct:"Can I take a message for her?",meaning:"Tôi có thể nhận lời nhắn giúp cô ấy không?"},{correct:"I'll call back later.",meaning:"Tôi sẽ gọi lại sau."}]}},

  // ===== BÀI 35 (lesson 34) — Ôn tổng kết toàn khóa KET =====
  {lesson:34,content:{title:"1. Ôn tập tất cả các Thì",desc:"Hệ thống hóa lại 4 thì quan trọng nhất: Hiện tại đơn, Quá khứ đơn, Hiện tại hoàn thành, Tương lai.",formula:[{text:"Present/Past/Present Perfect/Future",classes:"bg-indigo-100 text-indigo-700 border-indigo-300 font-bold"}],practiceList:[{correct:"I work in an office every day.",meaning:"Tôi làm việc ở văn phòng mỗi ngày."},{correct:"I have already finished my homework.",meaning:"Tôi đã hoàn thành bài tập về nhà rồi."},{correct:"I will travel to Japan next year.",meaning:"Tôi sẽ đi du lịch Nhật Bản vào năm sau."}]}},
  {lesson:34,content:{title:"2. Ôn Câu bị động & Câu tường thuật",desc:"Chuyển đổi câu chủ động sang bị động và câu trực tiếp sang câu gián tiếp.",formula:[{text:"S + be + V(p.p) (bị động)",classes:"bg-purple-100 text-purple-700 border-purple-300 font-bold"},{text:"S + said/asked + ... (tường thuật)",classes:"bg-teal-100 text-teal-700 border-teal-300 font-bold"}],practiceList:[{correct:"The cake was made by my mother.",meaning:"Chiếc bánh được làm bởi mẹ tôi."},{correct:"She said she was happy.",meaning:"Cô ấy nói rằng cô ấy hạnh phúc."},{correct:"He asked where I lived.",meaning:"Anh ấy hỏi tôi sống ở đâu."}]}},
  {lesson:34,content:{title:"3. Phân biệt Câu điều kiện 1 & 2",desc:"Điều kiện có thật (loại 1) và không có thật (loại 2) ở hiện tại/tương lai.",formula:[{text:"Loại 1: If + HTĐ, will + V",classes:"bg-blue-100 text-blue-700 border-blue-300 font-bold"},{text:"Loại 2: If + QKĐ, would + V",classes:"bg-orange-100 text-orange-700 border-orange-300 font-bold"}],practiceList:[{correct:"If I have time, I will visit you.",meaning:"Nếu tôi có thời gian, tôi sẽ đến thăm bạn."},{correct:"If I had time, I would visit you.",meaning:"Nếu tôi có thời gian (giả định), tôi sẽ đến thăm bạn."},{correct:"If it rains, the match will be cancelled.",meaning:"Nếu trời mưa, trận đấu sẽ bị hủy."}]}},

  // ===== BÀI 36 (lesson 35) — Luyện đề thi KET thực hành =====
  {lesson:35,content:{title:"1. KET Reading Part 1 (Đọc biển hiệu)",desc:"Chiến lược đọc các loại thông báo, biển hiệu ngắn và chọn ý nghĩa tương đương.",formula:[{text:"Chú ý các từ cấm đoán, bắt buộc (must, no, not allowed)",classes:"bg-red-100 text-red-700 border-red-300 font-bold"}],practiceList:[{correct:"\"No photography\" means you must not take pictures.",meaning:"\"Cấm chụp ảnh\" nghĩa là bạn không được chụp hình."},{correct:"\"Staff only\" means visitors may not enter.",meaning:"\"Chỉ nhân viên\" nghĩa là khách không được vào."},{correct:"\"Open until 9 p.m.\" means it closes at 9.",meaning:"\"Mở đến 9 giờ tối\" nghĩa là nó đóng cửa lúc 9 giờ."}]}},
  {lesson:35,content:{title:"2. KET Writing Part 7 (Viết Email)",desc:"Viết email từ 35-45 từ phản hồi ba gợi ý cho sẵn (như lời cảm ơn, đề xuất thời gian, từ chối).",formula:[{text:"Chào hỏi + 3 ý trả lời + Kết thúc",classes:"bg-blue-100 text-blue-700 border-blue-300 font-bold"}],practiceList:[{correct:"Hi Mary, Thanks for the invitation. I'd love to come on Saturday. See you then!",meaning:"Chào Mary, Cảm ơn lời mời. Mình rất muốn đến vào thứ Bảy. Hẹn gặp lại nhé!"},{correct:"Dear Tom, I'm sorry I can't come. I have a test that day.",meaning:"Tom thân mến, Mình xin lỗi vì không thể đến. Mình có bài kiểm tra vào ngày đó."},{correct:"Could we meet at 5 instead? Let me know.",meaning:"Chúng ta có thể gặp lúc 5 giờ thay vào đó được không? Cho mình biết nhé."}]}},
  {lesson:35,content:{title:"3. KET Speaking Part 2 (Mô tả ảnh)",desc:"Kỹ năng miêu tả người, đồ vật và hoạt động trong một bức ảnh.",formula:[{text:"In the picture, I can see... / They are V-ing...",classes:"bg-green-100 text-green-700 border-green-300 font-bold"}],practiceList:[{correct:"In the picture, I can see a family in a park.",meaning:"Trong bức ảnh, tôi thấy một gia đình ở trong công viên."},{correct:"They are having a picnic together.",meaning:"Họ đang cùng nhau đi picnic."},{correct:"The weather looks sunny and warm.",meaning:"Thời tiết trông có vẻ nắng và ấm áp."}]}},
];

async function main() {
  console.log('🚀 Bắt đầu xây lại GRAMMAR cho en-ket...\n');

  const program = await prisma.program.findUnique({
    where: { code: 'en-ket' },
    include: { lessons: { orderBy: { orderIndex: 'asc' } } },
  });
  if (!program) throw new Error('❌ Không tìm thấy Program en-ket');
  console.log(`✅ Program: ${program.name} (id: ${program.id})`);

  const lessonMap = {};
  program.lessons.forEach((l) => { lessonMap[l.orderIndex] = l.id; });

  const lessonIds = Object.values(lessonMap);
  const deleted = await prisma.lessonContent.deleteMany({
    where: { lessonId: { in: lessonIds }, contentType: 'GRAMMAR' },
  });
  console.log(`🗑️  Đã xóa ${deleted.count} GRAMMAR cũ\n`);
  console.log(`📝 Đang seed ${GRAMMAR_DATA.length} grammar points...\n`);

  let ok = 0, fail = 0;
  for (const g of GRAMMAR_DATA) {
    const lessonId = lessonMap[g.lesson];
    if (!lessonId) { console.error(`❌ Không tìm thấy lesson orderIndex=${g.lesson}`); fail++; continue; }
    try {
      await prisma.lessonContent.create({
        data: { lessonId, contentType: 'GRAMMAR', content: JSON.stringify(g.content) },
      });
      ok++;
    } catch (e) {
      console.error(`❌ Bài ${g.lesson} — "${g.content.title}": ${e.message}`);
      fail++;
    }
  }

  console.log('\n========== KẾT QUẢ ==========');
  console.log(`✅ Thành công : ${ok} grammar points`);
  console.log(`❌ Thất bại  : ${fail} grammar points`);
  console.log(ok === 108 ? '\n🎉 Hoàn thành! 108 grammar points đã được seed.' : '\n⚠️  Kiểm tra lỗi phía trên.');
}

main()
  .catch((e) => { console.error('\n❌ Lỗi:', e.message); process.exit(1); })
  .finally(async () => { await prisma.$disconnect(); });
